INSERT INTO Jeu_Jeu_chasse_anomalies (image_url, titre_image, coordonnes_anomalie_json, explication, points_accordes) VALUES
('Une photo de famille prise dans un jardin ensoleillé, montrant un père, une mère et deux enfants souriants autour d''une table de pique-nique avec des assiettes et des verres remplis de nourriture.', 'Portrait Familial', '["Le père a six doigts à la main droite.", "Les ombres des personnes ne correspondent pas à la direction du soleil."]', 'Cette image semble normale au premier abord, mais les anomalies comme les doigts supplémentaires et les ombres incohérentes sont des signes typiques d''une génération par IA qui a du mal à reproduire l''anatomie humaine et les lois de la physique.', 10);
INSERT INTO Jeu_Jeu_chasse_anomalies (image_url, titre_image, coordonnes_anomalie_json, explication, points_accordes) VALUES
('Une vue panoramique d''une ville moderne avec des gratte-ciels, des voitures circulant dans les rues et des piétons marchant sur les trottoirs, sous un ciel bleu clair.', 'Paysage Urbain', '["Un bâtiment a des fenêtres qui se chevauchent de manière impossible.", "Une voiture flotte légèrement au-dessus de la route."]', 'L''IA peut créer des scènes urbaines convaincantes, mais des erreurs comme des structures architecturales impossibles ou des objets en lévitation révèlent son incapacité à maintenir la cohérence spatiale.', 10);
INSERT INTO Jeu_chasse_anomalies (image_url, titre_image, coordonnes_anomalie_json, explication, points_accordes) VALUES
('', '', '"Le chat a trois yeux.\n"La balle de laine a des motifs qui se répètent de façon symétrique parfaite.', 'Bien que l''image paraisse mignonne, les anomalies comme les yeux supplémentaires et les motifs trop parfaits indiquent une génération par IA qui ne respecte pas la biologie animale ou les lois de la nature.', 10);
INSERT INTO Jeu_chasse_anomalies (image_url, titre_image, coordonnes_anomalie_json, explication, points_accordes) VALUES
('', '', '"La mère a une main avec seulement trois doigts.\n"Les reflets dans les verres ne correspondent pas aux objets autour.', 'Les repas familiaux sont courants, mais les doigts manquants et les reflets incorrects sont des erreurs fréquentes de l''IA lors de la génération d''images réalistes.', 10);
INSERT INTO Jeu_chasse_anomalies (image_url, titre_image, coordonnes_anomalie_json, explication, points_accordes) VALUES
('Plage Tropicale', 'Une plage de sable fin avec des palmiers, des vagues s''écrasant doucement et des personnes se relaxant sous des parasols colorés.', '"Un palmier a des feuilles qui poussent vers le bas au lieu de vers le haut.\n"Les ombres des parasols sont orientées dans des directions opposées.', 'Les scènes tropicales sont attrayantes, mais l''IA peut inverser des éléments naturels comme la croissance des plantes ou créer des incohérences dans les ombres.', 10);
INSERT INTO Jeu_chasse_anomalies (image_url, titre_image, coordonnes_anomalie_json, explication, points_accordes) VALUES
('', '', '"Un livre ouvert a du texte qui se répète indéfiniment.\n"Les ombres des lampes ne touchent pas le sol.', 'Les bibliothèques semblent intellectuelles, mais des textes répétitifs et des ombres flottantes trahissent l''origine artificielle de l''image.', 10);
INSERT INTO Jeu_chasse_anomalies (image_url, titre_image, coordonnes_anomalie_json, explication, points_accordes) VALUES
('Concert en Plein Air', 'Un groupe de musiciens jouant sur une scène en extérieur, avec un public assis sur l''herbe et des lumières colorées.', '"Un musicien a un instrument avec des cordes qui se croisent de façon impossible.\n"Le public a des visages identiques.', 'Les concerts sont dynamiques, mais l''IA peut créer des instruments déformés et des visages clonés, révélant son manque de créativité originale.', 10);
INSERT INTO Jeu_chasse_anomalies (image_url, titre_image, coordonnes_anomalie_json, explication, points_accordes) VALUES
('', '', '"Un robinet a de l''eau qui coule vers le haut.\n"Les poignées des tiroirs sont asymétriques.', 'Les cuisines modernes paraissent fonctionnelles, mais des éléments physiques impossibles comme l''eau inversée montrent les limites de l''IA.', 10);
INSERT INTO Jeu_chasse_anomalies (image_url, titre_image, coordonnes_anomalie_json, explication, points_accordes) VALUES
('', '', '"Un arbre a des branches qui forment des cercles parfaits.\n"Les fleurs ont des pétales qui se répètent exactement.', 'La nature semble magique, mais les formes géométriques parfaites et les répétitions indiquent une génération par IA sans variation naturelle.', 10);
INSERT INTO Jeu_chasse_anomalies (image_url, titre_image, coordonnes_anomalie_json, explication, points_accordes) VALUES
